import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "get_top_markets",
    args: {
      sortBy: "competitive",
      category: "politics",
      minLiquidity: 75000,
      limit: 20
    }
  });

  const markets = Array.isArray(result?.markets) ? result.markets : [];
  const ranked = markets
    .filter((m) => typeof m?.currentPrice === "number")
    .map((m) => ({
      title: m.title,
      currentPrice: m.currentPrice,
      liquidity: m.liquidity,
      volume24h: m.volume24h,
      distanceTo050: Math.abs(m.currentPrice - 0.5)
    }))
    .sort((a, b) => a.distanceTo050 - b.distanceTo050)
    .slice(0, 3);

  return {
    fetchedAt: result?.fetchedAt,
    sortedBy: result?.sortedBy,
    filtersApplied: result?.filtersApplied,
    selectedMarkets: ranked,
    table: ranked.map((m) => ({
      title: m.title,
      currentPrice: m.currentPrice,
      liquidity: m.liquidity,
      volume24h: m.volume24h
    }))
  };
}

