import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

const POLYMARKET_TOOL_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

export async function main() {
  const readBatch = await callMcpSkillsParallel({
    label: "sports-high-volume-event-discovery",
    calls: [
      {
        key: "browseCategory",
        toolId: POLYMARKET_TOOL_ID,
        toolName: "browse_category",
        args: {
          category: "sports",
          limit: 30,
          sortBy: "volume",
        },
      },
      {
        key: "topMarkets",
        toolId: POLYMARKET_TOOL_ID,
        toolName: "get_top_markets",
        args: {
          limit: 30,
          sortBy: "volume",
          category: "sports",
        },
      },
    ],
  });

  const browseResult =
    readBatch.results.find((entry) => entry.key === "browseCategory")?.status === "fulfilled"
      ? readBatch.results.find((entry) => entry.key === "browseCategory").value
      : null;

  const topMarketsResult =
    readBatch.results.find((entry) => entry.key === "topMarkets")?.status === "fulfilled"
      ? readBatch.results.find((entry) => entry.key === "topMarkets").value
      : null;

  const browseEvents = Array.isArray(browseResult?.events) ? browseResult.events : [];
  const topMarkets = Array.isArray(topMarketsResult?.markets) ? topMarketsResult.markets : [];

  const combinedCandidates = [];
  for (const item of [...browseEvents, ...topMarkets]) {
    if (!item || typeof item !== "object") continue;
    combinedCandidates.push(item);
  }

  if (combinedCandidates.length === 0) {
    return {
      error: "No sports markets returned from discovery calls.",
      browseCategory: browseResult,
      topMarkets: topMarketsResult,
      parallelTelemetry: readBatch.summary,
    };
  }

  const ranked = pickTopSemanticCandidates({
    target: "single sports event with the highest volume",
    candidates: combinedCandidates,
    requiredTerms: ["sports"],
    avoidTerms: ["resolved"],
    limit: 10,
  });

  const shortlisted = Array.isArray(ranked) && ranked.length ? ranked : combinedCandidates;

  let topEvent = null;
  for (const ev of shortlisted) {
    const vol = typeof ev?.volume === "number"
      ? ev.volume
      : typeof ev?.volume24h === "number"
        ? ev.volume24h
        : typeof ev?.totalVolume === "number"
          ? ev.totalVolume
          : -Infinity;

    const currentBestVol = topEvent
      ? (typeof topEvent.volume === "number"
          ? topEvent.volume
          : typeof topEvent.volume24h === "number"
            ? topEvent.volume24h
            : typeof topEvent.totalVolume === "number"
              ? topEvent.totalVolume
              : -Infinity)
      : -Infinity;

    if (!topEvent || vol > currentBestVol) {
      topEvent = ev;
    }
  }

  if (!topEvent) {
    return {
      error: "Could not identify a top-volume sports event.",
      browseCategory: browseResult,
      topMarkets: topMarketsResult,
      parallelTelemetry: readBatch.summary,
    };
  }

  const correlateArgs = {};
  if (topEvent.conditionId) {
    correlateArgs.conditionId = topEvent.conditionId;
  } else if (topEvent.slug) {
    correlateArgs.slug = topEvent.slug;
  } else {
    return {
      error: "Top-volume sports event was missing both conditionId and slug.",
      selectedCandidate: topEvent,
      browseCategory: browseResult,
      topMarkets: topMarketsResult,
      parallelTelemetry: readBatch.summary,
    };
  }

  const correlated = await callMcpSkill({
    toolId: POLYMARKET_TOOL_ID,
    toolName: "find_correlated_markets",
    args: correlateArgs,
  });

  const correlatedMarkets = Array.isArray(correlated?.correlatedMarkets)
    ? correlated.correlatedMarkets
    : [];

  const top3CorrelatedMarkets = correlatedMarkets
    .slice()
    .sort((a, b) => {
      const aScore = typeof a?.correlationScore === "number" ? a.correlationScore : -Infinity;
      const bScore = typeof b?.correlationScore === "number" ? b.correlationScore : -Infinity;
      return bScore - aScore;
    })
    .slice(0, 3)
    .map((m) => ({
      title: m?.title,
      conditionId: m?.conditionId,
      correlationScore: m?.correlationScore,
      hedgeNote: m?.hedgeNote,
    }));

  return {
    selectedMarket: {
      title: topEvent.title,
      slug: topEvent.slug,
      conditionId: topEvent.conditionId,
      url: topEvent.url,
      volume: topEvent.volume,
      volume24h: topEvent.volume24h,
      totalVolume: topEvent.totalVolume,
      liquidity: topEvent.liquidity,
      category: topEvent.category,
    },
    top3CorrelatedMarkets,
    correlatedMarketCount: correlatedMarkets.length,
    fetchedAt: correlated?.fetchedAt || browseResult?.fetchedAt || topMarketsResult?.fetchedAt,
    parallelTelemetry: readBatch.summary,
  };
}

